import{_ as a,o as n,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Products","description":"","frontmatter":{"title":"Products","slug":"products"},"headers":[],"relativePath":"marketer-hub/products.md","filePath":"marketer-hub/products.md"}'),r={name:"marketer-hub/products.md"};function o(s,e,c,l,p,d){return n(),t("div",null,[...e[0]||(e[0]=[i('<p>Branch is the go-to partner for marketers aiming to improve user engagement and ad performance.</p><p>Use Branch to validate and optimize your paid spend with better ad measurement and insights, even as the industry evolves.</p><p>At the same time, use it to grow your owned and organic channels, fueled by personalized links and campaigns. We aim to help you drive your customers to cost-effective channels (like your app) to accelerate your digital transformation.</p><p>The Branch Growth Platform offers three main product offerings: <strong>Engagement</strong>, <strong>Performance</strong>, and <strong>Activation</strong>.</p><h2 id="engagement" tabindex="-1">Engagement <a class="header-anchor" href="#engagement" aria-label="Permalink to &quot;Engagement&quot;">​</a></h2><p>With personalized creative campaigns and <strong>reliable linking</strong> experiences, Engagement ensures a seamless customer experience across email, social, web, and even offline.</p><p>The Engagement product empowers marketers to overcome their biggest pain points by maximizing the impact of <strong>owned and organic channels</strong>.</p><p>Branch&#39;s best-in-class App (deep) Links, QR Codes, and Journeys (smart banners) <strong>boost engagement and conversions</strong>, while clear cross-channel insights help you optimize the customer experience as users move across your platforms.</p><p>Our Engagement product helps eliminate broken experiences, enhance team efficiency, and <strong>improve customer lifetime value</strong> (LTV) with intuitive tools that create cohesive, targeted messages that engage and convert.</p><p>With advanced A/B testing, targeting, and customization, growth-focused teams can further drive traffic and optimize conversions among their users.</p><h3 id="in-action" tabindex="-1">In Action <a class="header-anchor" href="#in-action" aria-label="Permalink to &quot;In Action&quot;">​</a></h3><p>Take a look at a few of our favorite Engagement features and preview some ways to get started with them.</p><p><strong>Deep Linking</strong></p><p>Get peace of mind that your links will work in every edge case to route users to the best destination, while also getting the industry’s highest matching accuracy.</p><ul><li>Use Branch in social media channels, blog posts, and influencer networks with analytics tags and social previews.</li><li>Directly deep link users who have the app installed already to relevant content, such as specific product pages.</li><li>Take users who do not have the app installed to relevant content immediately after the first install, using deferred deep linking.</li></ul><p><strong>QR Codes</strong></p><p>Drive app adoption and engagement from offline, or cross-device engagement, with app-enabled QR codes.</p><ul><li>Customize Branch QR Codes to increase brand recognition and conversions.</li><li>Update destinations behind the Branch QR Codes to keep campaigns fresh.</li><li>Create Branch QR Codes one-off or at scale to drive app adoption from in-store signage, flyers, or posters.</li></ul><p><strong>Journeys</strong></p><p>Use smart banners (Journeys) to seamlessly move users to specific in-app content from the mobile web or desktop, driving app adoption and engagement on your highest performing platform.</p><ul><li>Carry context from the web into an app session, so a user can continue their journey in app.</li><li>Customize and A/B test banner creatives to increase web-to-app conversions.</li><li>Target desktop users with a post-purchase interstitial to install your app, creating cross-platform users.</li></ul><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>Our Performance product is ideal for measuring and optimizing campaign performance.</p><p>With Performance, you can <strong>understand true campaign ROI</strong> by leveraging privacy-preserving predictive modeling that accurately attributes conversions and provides visibility into ongoing app activity. Get consolidated cost data to maximize your marketing budget and see how ad spend drives results.</p><p>Focus on strategic growth and campaign optimization, knowing Branch will handle the complexities of performance tracking in today&#39;s world.</p><p>Take your campaigns one step further by bridging the gap between household devices with Performance, so you can finally start seeing how your TV advertising efforts are impacting your downstream conversions.</p><p>Importantly, Performance helps make sure you&#39;re protecting your ad budget from fraud and eliminating low-quality traffic. We help detect and prevent even the most sophisticated fraud with flexible blocking rules, dashboard visibility, and hands-on fraud mitigation support.</p><h3 id="in-action-1" tabindex="-1">In Action <a class="header-anchor" href="#in-action-1" aria-label="Permalink to &quot;In Action&quot;">​</a></h3><p>Below are some key Performance features alongside some suggested ways to get started with them.</p><p><strong>Attribution</strong></p><p>Optimize campaign performance and track your full return on investment in one place, using deduplicated data from every channel and platform.</p><ul><li>Power seamless customer experiences with links that just work, while capturing data at each touchpoint so you get a unified view of your customer.</li><li>Use last-touch attribution to identify which specific ad or channel drove the final conversion, making it easy to allocate budget to the top-performing channels, ensuring maximum ROI from ad spend.</li><li>Use Branch&#39;s Predictive Aggregate Measurement system to reduce reliance on privacy frameworks like SKAN, while still maintaining durable attribution strategies.</li></ul><p><strong>Engagement Builder</strong></p><p>Get greater return on ad spend (ROAS) with high-value users by re-engaging lapsed users, boost propensity to purchase, and increase sessions per user.</p><ul><li>Eliminate wasted spend in acquisition campaigns by effectively excluding existing customers.</li><li>Build audiences based on criteria, including advertising exposure across multiple ad networks, app and web interactions through owned and earned marketing channels, past purchases, in-app behavior, and more.</li><li>Generate audiences that respect user choice by automatically excluding end users who opt-out of ads personalization via platform-level privacy frameworks.</li></ul><p><strong>Household Measurement</strong></p><p>Branch’s attribution support for TV advertising allows you to measure down-funnel events, giving you a holistic view of your users&#39; journeys and the data you need to optimize your campaigns.</p><ul><li>Attribute app install and downstream conversion events to the correct ad partner when a user sees an ad for your app on a platform like Roku and downloads it.</li><li>Understand the influence CTV ads have on downstream conversion events across mobile, web, and desktop devices.</li><li>Improve retargeting efforts by providing ad partners with conversion events they can&#39;t track on their own.</li></ul><p><strong>Fraud Defense</strong></p><p>Help prevent wasted spend with higher quality data based on a privacy-preserving attribution model. Branch&#39;s fraud defense practices combine highly accurate detection with quick response, leaving you with data you can feel confident in.</p><ul><li>Set a &quot;Suspicious Device&quot; fraud rule to block installs from fake devices or emulators.</li><li>Use fraud analytics reporting to view blocked events and see why they were blocked.</li><li>See a snapshot of core fraud metrics that allow you to quickly analyze fraud detection performance.</li></ul><h2 id="activation" tabindex="-1">Activation <a class="header-anchor" href="#activation" aria-label="Permalink to &quot;Activation&quot;">​</a></h2><p><em>[Image: Mobile and desktop interface showcasing social media engagement and advertising features.]</em>.png)Address common challenges in link creation and analytics with a more streamlined approach.</p><p>Branch Activation is an enterprise custom QR and link shortening offering enabling you to activate your customers with web links, app links, and QR codes, and report on user interactions at scale.</p><p>Activation simplifies how you generate branded web Links, app Links, and QR codes, providing dedicated click insights without requiring complex SDK setups for your web campaigns.</p><p>You can create effective, measurable links for high-visibility channels like social media and SMS.</p><p>Unify your linking strategy on one secure, scalable platform. Improve click-through rates with branded links, reduce vendor complexities, and benefit from enterprise-grade governance—all while supporting your teams in executing their campaigns efficiently.</p><h3 id="in-action-2" tabindex="-1">In Action <a class="header-anchor" href="#in-action-2" aria-label="Permalink to &quot;In Action&quot;">​</a></h3><p>Explore how Activation’s key capabilities can enhance your marketing efforts.</p><ul><li>Improve clickthrough rates and engagement with short, branded, trackable links in social posts and profiles.</li><li>Create and manage web and app links and QR codes in one platform to reduce redundancy and unify analytics across use cases.</li><li>Improve efficiency and gain control with centralized link governance, domain management, and role-based permissions.</li><li>Instill trust and boost clickthrough rates with recognizable branded links and QR codes.</li></ul><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>To learn more about Branch’s different products and packages, visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing page</a> or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our sales team</a>.</p>',52)])])}const h=a(r,[["render",o]]);export{g as __pageData,h as default};
